var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"제길! 대체 저 괴상한 로봇은 뭔데 끝도 없이 일어서는 거야?","JPN":"くそ！　あの妙なロボットはおきあがりこぼしか？\\n倒しても倒しても起き上がってきやがる。","ENG":"Drat! Why wouldn't that stupid robot stay down?","TWN":"該死！那奇怪的機器人為什麼能不斷地站起來？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"아빠가 날 지켜주는 한 우린 무적이야! 그러니 포기하시지!","JPN":"パパが私を守ってくれる限り、私たちは無敵だよ！\\nだから、いい加減観念して！","ENG":"We're invincible so long as Daddy's with us! You'd better give up!","TWN":"只要有爸爸在，我們就是無敵的！快投降吧！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"에잇! 헛소리 집어 치워! 기계면 기계답게 사람에게 복종하라고!","JPN":"ええいっ！　バカ言うな！　機械なら機械らしく\\n人間に服従しろ！","ENG":"Eek! Shut up! You're a machine—act like one!","TWN":"可惡！給我住口！機器還是乖乖服從人類吧！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"어머, 우리 예비 사장님께 말투가 그게 뭐죠? 예의 없게시리.","JPN":"あら、未来の社長に向かってそんな口の利き方は\\nないでしょう。礼儀知らずね。","ENG":"You shouldn't talk to our future president like that. That's rude.","TWN":"咦，你怎麼這麼對我們的未來老闆說話？太沒禮貌了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L16_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"크윽!","JPN":"くっ！","ENG":"Gah!","TWN":"呃呃！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"조, 좋아! 너도 언더그라운드에서 활동하는 녀석들이니 돈이 필요하겠지?","JPN":"こ、こうしよう！　お前らもアンダーグラウンドで\\n活動してるんだし、金が必要だろ？","ENG":"O-okay! You're from the Underground. You like money, right?","TWN":"對了！你也是在地下世界活動的傢伙，肯定需要錢吧？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"협상, 협상을 하자!","JPN":"交渉、交渉をしよう！","ENG":"Parley. I invoke the right of parley!","TWN":"我們來談判吧，談判！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"지금 내 편을 들어준다면 저쪽에서 지불한 금액의 두 배, 아니 세 배를 지불하겠어!","JPN":"俺の味方をしてくれたら向こうの2倍、いや3倍をやる！","ENG":"Help me, and I'll pay you twice—no, three times the amount that they paid you.","TWN":"你如果加入到我們這一邊，我就付你兩倍，不，三倍的價錢！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"거 참 흥미로운 제안이네요.","JPN":"実に興味深いご提案ですね。","ENG":"That's an interesting offer.","TWN":"真是一個有趣的提議。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"크큭, 그래. 그렇게 나와야지. 그럼 어서 날 도와서 저것들을......","JPN":"ククッ。そう来なくっちゃ。じゃあ、俺と一緒にあいつらを……","ENG":"Heh heh, yes, that's more like it. Now, help me get rid of—","TWN":"嘿嘿，沒錯，這就對了。快幫我把那些傢伙……"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그런데 누가 언더그라운드라는 거죠?","JPN":"でも、誰がアンダーグラウンドで活動してるって？","ENG":"But who's from the Underground?","TWN":"不過你說誰是地下世界的人？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"저흰 엄연히 관리국의 정.식.라.이.선.스 를 보유한 팀이라서요.","JPN":"私たちは管理局お墨付きの「ラ・イ・セ・ン・ス」を\\nもらってますからね。","ENG":"We've been OFFICIALLY LICENSED by the Administration.","TWN":"我們擁有管理局的正——式——執——照。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아쉽게도 조건부적합으로 그 제안은 받아들일 수 없겠네요.","JPN":"残念ながら条件を満たしていないので、その提案は\\n受け入れられませんね。","ENG":"I'm sorry, but we can't meet your condition or offer.","TWN":"很遺憾你不符合條件，不能接受你的提議。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"이, 이 녀석들이!","JPN":"こ、この野郎！","ENG":"Y-you jerk!","TWN":"你、你們！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"날 가지고 놀아?!","JPN":"俺のことをバカにしてるのか！？","ENG":"How dare you play with me?","TWN":"竟敢耍我？！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"전 기체! 이제 싸움을 끝낼 때가 왔다!","JPN":"諸君！　決着をつける時がきたぞ！","ENG":"Everyone, it's time to put an end to this.","TWN":"所有機體！是時候結束這場戰鬥了！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_29"},{"id":"L31_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"내 조준에 따라 적을 향해 일제 사격 개시!","JPN":"吾輩の照準に合わせて、敵に向かって一斉射撃を開始！","ENG":"Follow my lead and fire at the enemy!","TWN":"聽我指令，向敵人集火！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"허억...... 허억......","JPN":"はあ……はあ……","ENG":"Huff, huff...","TWN":"呵……呵……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"망할 녀석들...... 그놈들 때문에 함선도, 부하들도 모두 잃어버렸어.","JPN":"クソ野郎どもめ……あいつらのせいで艦船も部下も、\\n何もかも失ってしまった。","ENG":"Those freaks... I've lost my ship and men because of them.","TWN":"該死……他們破壞了我的艦船，殺光了我的部下。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"하지만 이게 끝이라고 생각하지 마라.","JPN":"だが、これですべてが終わったと思うなよ。","ENG":"But this isn't over.","TWN":"但別以為就這樣算了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"찰거머리단은 결코 포기를 모르는......! 음?","JPN":"粘着海賊団は決して諦めたりしない……！　ん？","ENG":"We Leeches never give up—mm?","TWN":"血蛭團永遠不會放棄……！嗯？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L40_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"어딜 그렇게 급하게 가시죠, 해적 두목님?","JPN":"急ぎ足でどこに向かってるんですか、海賊の親玉さん？","ENG":"Where do you think you're going, Pirate Captain?","TWN":"你急著去哪裡，海盜頭目大人？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"......끼야아앗!","JPN":"……ぐあああっ！","ENG":"Kyaaaaah!","TWN":"……啊啊啊啊！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L43_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"어, 어떻게? 내가 여기로 도망칠 거라는 걸 알고 있었지?!","JPN":"な、なぜだ？　どうして俺の行先がわかったんだ！？","ENG":"H-how? How did you know I'd come here?","TWN":"怎麼會？你怎麼知道我會從這裡逃走？！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"혼란스런 와중에 요리조리 빠져나가는 건 제 특기라서요.","JPN":"混乱の中で抜け道を探すのが私の得意技ですから。","ENG":"I know a thing or two about slipping out of danger in the thick of confusion.","TWN":"因為從混亂中脫身是我的專長。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"왠지 이쪽으로 오지 않을까 해서 혼자 기다렸는데, 딱 걸리셨네요.","JPN":"なんとなくこっちかな、とひとりで待ち伏せしてみたら\\nビンゴだったわけです。","ENG":"I waited here alone, thinking you might come this way. And you did.","TWN":"我猜你會到這邊來，所以一個人等著，沒想到真猜中了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"혼자라고......?","JPN":"ひとりだって……？","ENG":"You came alone?","TWN":"你一個人……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"하하하! 이것 참 나도 얕잡아 보였군.","JPN":"ハハハ！　俺のことをずいぶん見くびっているな。","ENG":"Hah hah! You really underestimate me, don't you?","TWN":"哈哈哈！我竟然被看扁了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"비록 조금 전에는 <color=#ffd34c>전략적 후퇴</color>를 하긴 했지만 나 역시 언더그라운드의 대해적 중 한 명!","JPN":"さっきは<color=#ffd34c>戦略的退却</color>を選んだが、\\n俺もアンダーグラウンドきっての大海賊のひとり！","ENG":"I may have made a <color=#ffd34c>strategic retreat</color> this time, but I'm one of the greatest pirates in the Underground!","TWN":"雖然之前我不得不<color=#ffd34c>戰略性撤退</color>，但我畢竟也是地下世界的大海盜之一！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"고유무장도 없이 일반 병기나 쓰는 3류 카운터 주제에 겨우 너 혼자서 나를 상대할......","JPN":"固有武装もなく一般兵器しかない3流カウンターのくせに、\\nたったひとりで俺に歯向かうなんて……","ENG":"I'm not someone you can mess with. You're just a third-rate Counter without Unique Gear or—","TWN":"連專屬裝備都沒有的三流制裁者竟敢一個人與我……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"응? 방금 뭐라고 했어?","JPN":"え？　今、なんて？","ENG":"Huh? What did you just say?","TWN":"嗯？你說什麼？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_08"},{"id":"L3_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"아, 고유무장? 혹시 이런 거 말하는 건가?","JPN":"あ、固有武装？　もしかしてこれのことかな？","ENG":"Oh, did you say Unique Gear? You mean... like this?","TWN":"啊，專屬裝備？是說這個嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"자, 우리 대해적 아줌마에겐 두 개의 선택권이 있어요.","JPN":"さあ、大海賊のオバサンには二つの選択肢があるわよ。","ENG":"Now, Pirate Lady. You have two choices.","TWN":"好，我們大海盜阿姨現在有兩個選擇。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"첫째, 나한테 잡혀서 경찰서까지 끌려간다.","JPN":"ひとーつ。私に捕まって、警察署まで連れていかれる。","ENG":"One, you can surrender and follow me to the police station.","TWN":"第一，和我一起走到警察局。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"둘째, 나한테 맞아서 경찰서까지 날아간다.","JPN":"ふたーつ。私にボコボコにされた後、警察署まで\\nぶっ飛ばされる。","ENG":"Two, or you can be dragged there after a good beating.","TWN":"第二個，被我一腳踢飛到警察局。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"어쩔래?","JPN":"どっちにします？","ENG":"Which one?","TWN":"你怎麼選？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"......처, 첫째로 하겠습니다.","JPN":"……ひ、ひとつ目にします。","ENG":"I-I'll take the first.","TWN":"……我、我選第一個。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"현명한 선택이에요, 이걸로 오늘도 한 건 해결!","JPN":"賢明な判断だわ。これで今日も一件落着ね！","ENG":"You've made a smart choice. Case solved!","TWN":"明智的選擇，今天又搞定了一件！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_SEO_YOON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"우여곡절 끝에 열쇠를 얻은 소녀는 동물들을 무사히 풀어주었습니다.","JPN":"紆余曲折の末、カギを手に入れた少女は\\n動物たちを無事解放しました。","ENG":"After several twists and turns, the girl found the key and released the animals.","TWN":"少女經過萬般苦難終於找到了鑰匙，她立刻救出了動物們。"},"stage":{"bg":"EV_SIGMA_07","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"곰은 소녀에게 답례하기 위해 요정이 살고 있는 집을 알려줬습니다.","JPN":"クマは少女へのお礼に、妖精の居所を教えました。","ENG":"The bear told her where the fairy lived in return for her help.","TWN":"熊為了報答少女，把妖精的住址告訴了她。"},"stage":{"bg":"EV_SIGMA_07","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"사자는 소녀를 위해 요정이 있는 산꼭대기까지 태워주었어요.","JPN":"ライオンは少女へのお礼に、妖精がいる山頂まで背中にのせてくれました。","ENG":"The lion gave her a ride to the top of the mountain where the fairy stayed.","TWN":"獅子讓少女騎在自己身上，把她送到了妖精所在的山頂上。"},"stage":{"bg":"EV_SIGMA_07","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"소녀는 요정을 만났고, 그 요정이 자신에게 생명을 주었음을 알게 됐습니다.","JPN":"少女は妖精に会い、その妖精によって自分の命が\\n与えられたことを知りました。","ENG":"The girl met the fairy and realized that she was the one who gave her life.","TWN":"少女終於見到了妖精，並瞭解到是妖精為自己賦予了生命。"},"stage":{"bg":"EV_SIGMA_08","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"요정은 세월이 흘러 약속한 5년이 지나자, 나무꾼의 생명이 다했을 뿐이라고 알려줬습니다.","JPN":"妖精は、約束した5年が経ったので木こりの寿命が\\n尽きたのだと教えてくれました。","ENG":"The fairy said that the woodcutter died because the five years of time allowed to him had expired.","TWN":"妖精說，樵夫之所以失去生命是因為當時說好的5年時限到了。"},"stage":{"bg":"EV_SIGMA_08","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"소녀는 자신이 받은 생명을 돌려줄 테니 나무꾼을 살려달라고 부탁했습니다.","JPN":"少女は、自分に与えられた命を返すので木こりを\\n助けてほしいと頼みました。","ENG":"The girl said she'd give up her life if she could bring the woodcutter back to life.","TWN":"少女懇求妖精用自己的生命為代價救活樵夫。"},"stage":{"bg":"EV_SIGMA_08","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"요정은 잠시 망설였어요.","JPN":"妖精はしばらく悩みました。","ENG":"The fairy hesitated.","TWN":"妖精猶豫了一下。"},"stage":{"bg":"EV_SIGMA_08","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 소녀가 곰과 사자를 구해준 은인이란 말을 듣고는 결정을 내렸습니다.","JPN":"しかし、少女がクマやライオンを助けた恩人だと知り、ついに決断しました。","ENG":"But after hearing the girl had saved the bear and the lion, the fairy made a decision,","TWN":"但瞭解到少女是熊和獅子的救命恩人之後終於下了決定。"},"stage":{"bg":"EV_SIGMA_08","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"그녀가 숲의 동물들을 위해 선행을 베풀었으니 특별히 허락해주기로 말이죠.","JPN":"彼女が森の動物たちのために尽くしてくれたので、\\n特別に許可することにしたのです。","ENG":"to grant the girl her wish in return for her help to the animals in the forest.","TWN":"少女幫助了森林的動物們，於是決定答應她的請求。"},"stage":{"bg":"EV_SIGMA_08","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"다만, 나무꾼에게 생명을 돌려주면 그녀가 가진 소녀의 모습은 다시 잃게 될 것이라고 했습니다.","JPN":"ただし、木こりに命を返すと少女は現在の姿を失うことに\\nなると告げました。","ENG":"The fairy, however, warned the girl that she'd lose her human form once the woodcutter was brought back to life.","TWN":"但妖精說，如果救活樵夫，少女會變回之前的人偶模樣。"},"stage":{"bg":"EV_SIGMA_08","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"소녀는 조금도 망설이지 않고 그렇게 해달라고 했습니다.","JPN":"少女はほんの少しのためらいもなく、そうしてほしいと\\n言いました。","ENG":"The girl didn't care. She wanted him back.","TWN":"少女絲毫沒有猶豫，只求妖精趕快救活樵夫。"},"stage":{"bg":"EV_SIGMA_08","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"그녀에겐 아름다운 소녀의 모습보다, 가족이 더 소중했으니까요.","JPN":"彼女にとって大切なのは、美しい少女の姿よりも\\n家族のほうでした。","ENG":"To her, her family mattered more than her looks.","TWN":"因為對她來講，比起美麗的少女姿態，家人才是最重要的。"},"stage":{"bg":"EV_SIGMA_08","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"요정은 미소를 지으며, 이제 집으로 돌아가면 나무꾼이 깨어나있을 거라고 말했습니다.","JPN":"妖精はほほ笑み、家に帰れば木こりが目を覚ましている\\nだろうと告げました。","ENG":"The fairy smiled and said that the woodcutter would be awake by the time she got home.","TWN":"妖精微笑著說，回到家裡後應該能見到再次蘇醒的樵夫。"},"stage":{"bg":"EV_SIGMA_08","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"소녀가 집으로 돌아오자, 나무꾼은 정말 깨어나있었습니다.","JPN":"少女が家に帰ると、木こりは本当に目を覚ましていました。","ENG":"And he was.","TWN":"少女回家後發現，樵夫果然醒了過來。"},"stage":{"bg":"EV_SIGMA_09","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"둘은 다시 만난 것을 기뻐하며 서로를 품에 안았습니다.","JPN":"二人は再会できたことを喜び、抱き合いました。","ENG":"They hugged each other and rejoiced over their reunion.","TWN":"兩個人高興地相擁。"},"stage":{"bg":"EV_SIGMA_09","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"그 순간, 나무꾼은 소녀가 다시 나무인형으로 돌아왔음을 깨달았습니다.","JPN":"その瞬間、木こりは少女が木彫り人形に戻っていることに\\n気がつきました。","ENG":"Just then, the woodcutter realized that the girl was back to being a wooden doll.","TWN":"而在那時，樵夫發現少女再次變成了木偶。"},"stage":{"bg":"EV_SIGMA_10","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 서로가 가족이라는 것에는 아무런 변함도 없었죠.","JPN":"それでも、二人が家族であることに変わりはありません。","ENG":"That didn't change that they were family.","TWN":"但是他知道，他們始終是一家人。"},"stage":{"bg":"EV_SIGMA_10","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇기에 아버지는 아무 것도 묻지 않았습니다.","JPN":"だからこそ、お父さんは何も聞きませんでした。","ENG":"So, the father said nothing.","TWN":"所以樵夫什麼都沒有問。"},"stage":{"bg":"EV_SIGMA_10","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"대신 오랜 여정으로 차가워진 그녀의 몸이 따뜻해질 때까지 오래도록 끌어안았습니다.","JPN":"その代わりに長い旅で冷え切った彼女の体が温まるまで、\\nずっと抱きしめていました。","ENG":"Instead, he hugged his daughter's body that had frozen during her long journey until it became warm.","TWN":"只是緊緊地抱住了她，溫暖了她因長久的旅途而變涼的身體。"},"stage":{"bg":"EV_SIGMA_10","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"둘은 그렇게 행복하게 살았답니다.","JPN":"その後、二人はずっと幸せに暮らしましたとさ。\\nめでたし、めでたし。","ENG":"And just like that, they lived happily ever after.","TWN":"兩個人就這樣一起度過了幸福的一生。"},"stage":{"bg":"EV_SIGMA_10","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};